import 'https://cdn.jsdelivr.net/npm/img-comparison-slider@8/+esm';
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/img-comparison-slider@8/dist/styles.css'; document.head.appendChild(css);
const slider = document.createElement('img-comparison-slider'); slider.style.width = '100%'; slider.direction = data.direction ?? 'horizontal'; slider.value = data.position ?? 50;
for (const [slot, image] of [['first', data.before], ['second', data.after]]) { const img = document.createElement('img'); img.slot = slot; img.src = image.src; img.alt = image.alt ?? ''; img.style.cssText = `width:100%;height:360px;object-fit:${data.object_fit ?? 'cover'}`; slider.appendChild(img); }
if (data.hover) slider.setAttribute('hover', 'true'); if (data.keyboard === 'disabled') slider.setAttribute('keyboard', 'disabled');
document.getElementById('comparison').appendChild(slider);

